import xml.etree.ElementTree as ET

def validate_xml_document(xml_data):
    try:
        # Parse the XML data
        root = ET.fromstring(xml_data)
        
        # Perform basic validation checks
        if root is None:
            raise ValueError("XML document is empty")
        
        # Example specific tag validation
        # Check for a specific tag, e.g., 'element'
        element_tag = './/element'
        elements = root.findall(element_tag)
        if not elements:
            raise ValueError(f"Missing required element '{element_tag}' in XML")
        
        return True
    
    except ET.ParseError as e:
        print(f"XML parsing error: {e}")
        return False
    except ValueError as ve:
        print(f"Validation error: {ve}")
        return False

